{
  "summary": "This paper introduces MGSM, the first multilingual arithmetic reasoning benchmark with multi-step problems across ten typologically diverse languages, and systematically evaluates large language models using various multilingual chain-of-thought prompting strategies. The study demonstrates emergent multilingual reasoning abilities in large models, strong cross-lingual generalization, and sets new state-of-the-art results on related reasoning tasks, while releasing the benchmark publicly to foster future research.",
  "strengths": [
    {
      "point": "Introduction of MGSM, a novel multilingual arithmetic reasoning benchmark",
      "evidence": "MGSM covers ten typologically diverse languages with high-quality manual translations, enabling evaluation of multi-step reasoning in multilingual settings."
    },
    {
      "point": "Comprehensive evaluation of multilingual chain-of-thought prompting strategies",
      "evidence": "The paper explores DIRECT, NATIVE-COT, EN-COT, and TRANSLATE-EN prompting methods, showing that English CoT prompting is a strong baseline across languages."
    },
    {
      "point": "Demonstration of emergent multilingual reasoning abilities in large-scale LLMs",
      "evidence": "LLM-540B achieves over 40% accuracy on MGSM across all languages, including low-resource ones, with reasoning ability emerging notably at larger scales."
    },
    {
      "point": "Strong cross-lingual generalization beyond arithmetic reasoning",
      "evidence": "The model achieves state-of-the-art results on XCOPA commonsense reasoning and competitive results on XL-WiC semantic judgment with minimal supervision."
    },
    {
      "point": "Public release of benchmark and materials",
      "evidence": "The MGSM benchmark and supplementary materials are made publicly available to facilitate future research."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited comparison to prior multilingual reasoning benchmarks",
      "evidence": "The paper does not sufficiently discuss or compare MGSM to existing multilingual reasoning datasets like XQUAD, MLQA, or Math23K."
    },
    {
      "point": "Lack of justification for language selection",
      "evidence": "The choice of ten languages is stated but not justified in terms of linguistic diversity criteria or representativeness."
    },
    {
      "point": "No analysis of translation quality impact on model performance",
      "evidence": "Although translations are professionally done, the paper lacks ablation or error analysis comparing machine-translated versus human-translated problems."
    },
    {
      "point": "Insufficient prompt design details and no prompt sensitivity analysis",
      "evidence": "The paper does not provide details on prompt design, length, or exemplar selection criteria, nor does it analyze how prompt variations affect reasoning."
    },
    {
      "point": "Limited baselines in evaluation",
      "evidence": "Evaluation excludes other strong multilingual models like mT5, XLM-R large fine-tuned on reasoning tasks, BLOOM, or LLaMA, limiting comparative insights."
    },
    {
      "point": "Evaluation metrics focus solely on accuracy without detailed error analysis",
      "evidence": "No qualitative examples or analysis of typical failure modes are provided to understand error sources."
    },
    {
      "point": "Overstated interpretation of English CoT performance",
      "evidence": "The paper does not analyze whether EN-COT's strong performance is due to better English reasoning or translation artifacts, nor discuss practical implications."
    },
    {
      "point": "Insufficient reproducibility details",
      "evidence": "Details on proprietary LLM training data and procedure, prompt exemplars, and translation process (e.g., Google Translate settings) are missing."
    },
    {
      "point": "Ambiguity in defining 'reasoning steps' in MGSM",
      "evidence": "The paper does not operationalize or annotate how reasoning steps are counted, affecting clarity on problem complexity."
    },
    {
      "point": "No discussion of cultural or linguistic biases in translations",
      "evidence": "Potential biases from translating English math problems into other languages and their impact on reasoning are not addressed."
    },
    {
      "point": "Limited reasoning types and language/script coverage",
      "evidence": "Focus is mainly on arithmetic reasoning; languages with non-alphabetic scripts beyond Chinese or complex morphology are excluded."
    },
    {
      "point": "No evaluation on real-world noisy or code-switched multilingual inputs",
      "evidence": "Benchmark uses clean, carefully translated problems, limiting understanding of practical multilingual reasoning robustness."
    },
    {
      "point": "Insufficient explanation why CoT does not help XL-WiC",
      "evidence": "The paper only briefly speculates on this without detailed analysis or hypotheses."
    }
  ],
  "questions": [
    {
      "question": "How does MGSM compare in detail to existing multilingual reasoning benchmarks in terms of task complexity and language coverage?",
      "motivation": "Clarifying this would better situate the contribution and novelty of MGSM within the multilingual reasoning landscape."
    },
    {
      "question": "What criteria guided the selection of the ten languages, and how might inclusion of other languages with different scripts or morphology affect results?",
      "motivation": "Understanding language selection rationale is important for claims about typological diversity and generalizability."
    },
    {
      "question": "How sensitive are the results to translation quality and prompt design variations?",
      "motivation": "This impacts the robustness and reproducibility of findings and informs best practices for multilingual CoT prompting."
    },
    {
      "question": "What are the practical implications of relying on English chain-of-thought prompting for truly multilingual applications?",
      "motivation": "This affects usability in real-world multilingual settings where English intermediate reasoning may not be feasible."
    },
    {
      "question": "Can the benchmark and models handle more diverse reasoning types beyond arithmetic, such as logical deduction or causal reasoning?",
      "motivation": "This would clarify the scope and limitations of the approach and guide future extensions."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
